#!/usr/bin/env node
// Generated by OrchestKit Claude Plugin
// Created: 2026-04-19
//
// Validates a Claude Design handoff bundle against the schema documented
// in src/agents/claude-design-orchestrator.md. The real schema (observed
// during the #1399 dogfood) is a gzipped tarball with:
//
//   <project-name>/
//   ├── README.md                 (required)
//   ├── chats/*.md                (required — at least one)
//   └── project/*.html            (optional — absent = incomplete bundle)
//
// Usage:
//   node scripts/validate-handoff-bundle.mjs <path-to-bundle.tar.gz>
//
// Exit codes:
//   0 — valid (complete or incomplete-but-valid)
//   1 — invalid (structural violation)
//   2 — tool/IO error

import { existsSync, statSync, mkdtempSync, rmSync, readdirSync } from 'node:fs';
import { readFile } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { execFileSync } from 'node:child_process';

const arg = process.argv[2];
if (!arg) {
  console.error('Usage: node validate-handoff-bundle.mjs <path-to-bundle.tar.gz>');
  process.exit(2);
}
if (!existsSync(arg)) {
  console.error(`Bundle not found: ${arg}`);
  process.exit(2);
}

const stat = statSync(arg);
if (!stat.isFile() || stat.size === 0) {
  console.error(`Bundle is not a regular non-empty file: ${arg}`);
  process.exit(2);
}

// ─── extract into a tmp dir, then validate the tree ────────────────────
const tmp = mkdtempSync(join(tmpdir(), 'handoff-validate-'));
try {
  try {
    execFileSync('tar', ['-xzf', arg, '-C', tmp], { stdio: 'pipe' });
  } catch (e) {
    console.error('Failed to extract bundle (not a valid .tar.gz?):', e.message);
    process.exit(1);
  }

  // Expect exactly one top-level directory (the project name).
  const topEntries = readdirSync(tmp, { withFileTypes: true });
  const topDirs = topEntries.filter((e) => e.isDirectory());
  if (topDirs.length !== 1) {
    console.error(
      `Bundle must contain exactly one top-level directory; found ${topDirs.length}.`,
    );
    process.exit(1);
  }
  const projectName = topDirs[0].name;
  const projectDir = join(tmp, projectName);

  const findings = {
    projectName,
    hasReadme: false,
    chatCount: 0,
    htmlCount: 0,
    warnings: [],
    errors: [],
  };

  // README.md is required
  const readmePath = join(projectDir, 'README.md');
  if (existsSync(readmePath) && statSync(readmePath).isFile()) {
    findings.hasReadme = true;
    const content = await readFile(readmePath, 'utf8');
    if (!content.trim()) {
      findings.warnings.push('README.md is empty');
    }
    // The real Claude Design README is addressed to "CODING AGENTS". Soft check.
    if (!/coding agents|handoff bundle|claude\.ai\/design/i.test(content)) {
      findings.warnings.push(
        'README.md does not mention "CODING AGENTS", "handoff bundle", or "claude.ai/design" — may not be a real Claude Design bundle',
      );
    }
  } else {
    findings.errors.push(`Required file missing: ${projectName}/README.md`);
  }

  // chats/*.md is required — at least one transcript
  const chatsDir = join(projectDir, 'chats');
  if (existsSync(chatsDir) && statSync(chatsDir).isDirectory()) {
    const chatFiles = readdirSync(chatsDir).filter((f) => f.endsWith('.md'));
    findings.chatCount = chatFiles.length;
    if (chatFiles.length === 0) {
      findings.errors.push(`${projectName}/chats/ must contain at least one .md file`);
    }
  } else {
    findings.errors.push(`Required directory missing: ${projectName}/chats/`);
  }

  // project/*.html is optional — its absence means "incomplete bundle".
  const projSubdir = join(projectDir, 'project');
  let status = 'complete';
  if (existsSync(projSubdir) && statSync(projSubdir).isDirectory()) {
    const htmls = readdirSync(projSubdir).filter((f) => f.endsWith('.html'));
    findings.htmlCount = htmls.length;
    if (htmls.length === 0) {
      findings.warnings.push(
        `${projectName}/project/ exists but contains no .html — treating as incomplete`,
      );
      status = 'incomplete';
    }
  } else {
    status = 'incomplete';
  }

  // ─── report + exit ───────────────────────────────────────────────────
  if (findings.errors.length > 0) {
    console.error('✗ INVALID bundle:');
    for (const e of findings.errors) console.error(`  - ${e}`);
    if (findings.warnings.length > 0) {
      console.error('  warnings:');
      for (const w of findings.warnings) console.error(`    · ${w}`);
    }
    process.exit(1);
  }

  console.log(
    `✓ Valid bundle (${status}) — project=${findings.projectName}, ` +
      `chats=${findings.chatCount}, htmls=${findings.htmlCount}`,
  );
  if (findings.warnings.length > 0) {
    for (const w of findings.warnings) console.log(`  warn: ${w}`);
  }
  process.exit(0);
} finally {
  try {
    rmSync(tmp, { recursive: true, force: true });
  } catch {
    /* ignore cleanup errors */
  }
}
